// AuthInterceptor.kt
import okhttp3.Interceptor
import okhttp3.Response

class AuthInterceptor(private val tokenProvider: () -> String?) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val originalRequest = chain.request()
        val token = tokenProvider()
        
        val newRequest = if (token != null) {
            originalRequest.newBuilder()
                .header("Authorization", "Bearer $token")
                .build()
        } else {
            originalRequest
        }
        
        return chain.proceed(newRequest)
    }
}

// NetworkModule.kt
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {
    private var currentEnvironment: Environment = Environment.PRODUCTION
    private var authToken: String? = null
    
    fun setEnvironment(environment: Environment) {
        currentEnvironment = environment
    }
    
    fun setAuthToken(token: String?) {
        authToken = token
    }
    
    fun getAuthToken(): String? = authToken
    
    private val loggingInterceptor = HttpLoggingInterceptor().apply {
        level = HttpLoggingInterceptor.Level.BODY
    }
    
    private val authInterceptor = AuthInterceptor { authToken }
    
    private val okHttpClient = OkHttpClient.Builder()
        .addInterceptor(authInterceptor)
        .addInterceptor(loggingInterceptor)
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(30, TimeUnit.SECONDS)
        .build()
    
    private fun getRetrofit(): Retrofit {
        return Retrofit.Builder()
            .baseUrl(currentEnvironment.baseUrl)
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
    
    val apiService: ApiService by lazy {
        getRetrofit().create(ApiService::class.java)
    }
}

// NetworkResult.kt
sealed class NetworkResult<out T> {
    data class Success<T>(val data: T) : NetworkResult<T>()
    data class Error(val message: String, val code: Int? = null) : NetworkResult<Nothing>()
    object Loading : NetworkResult<Nothing>()
}

// UserRepository.kt
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import retrofit2.Response

class UserRepository {
    private val apiService = NetworkModule.apiService
    
    suspend fun getUsers(): NetworkResult<List<User>> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.getUsers()
            handleResponse(response)
        } catch (e: Exception) {
            NetworkResult.Error(e.message ?: "Unknown error occurred")
        }
    }
    
    suspend fun getUserById(userId: Int): NetworkResult<User> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.getUserById(userId)
            handleResponse(response)
        } catch (e: Exception) {
            NetworkResult.Error(e.message ?: "Unknown error occurred")
        }
    }
    
    suspend fun searchUsers(query: String): NetworkResult<List<User>> = withContext(Dispatchers.IO) {
        try {
            val response = apiService.searchUsers(query)
            handleResponse(response)
        } catch (e: Exception) {
            NetworkResult.Error(e.message ?: "Unknown error occurred")
        }
    }
    
    private fun <T> handleResponse(response: Response<T>): NetworkResult<T> {
        return if (response.isSuccessful) {
            response.body()?.let {
                NetworkResult.Success(it)
            } ?: NetworkResult.Error("Empty response body", response.code())
        } else {
            NetworkResult.Error(
                response.message() ?: "Request failed",
                response.code()
            )
        }
    }
}

